for (const item of $input.all()) {
  const json = item.json || {};


  // Evento
  const event = json.evento || "UNKNOWN";

  // Usu├бrio
  const userEmail = (json.user && json.user.email) ? json.user.email : "Desconhecido";

  // Exchange
  const exchange = json.exchange || "Desconhecida";

  // Bot Config
  const leverage = json.leverage || "N/A";
  const operationMode = json.operationMode || "N/A";

  // Mapeamento de modos
  const modeNames = { "auto_expiring": "Sniping", "counter_trend": "Contra Tend\u00eancia", "manual": "Manual" };
  const modeDisplay = modeNames[operationMode] || operationMode;

  // Dados do Trade
  const trade = json.trade || {};
  const symbol = trade.symbol || "N/A";
  const direction = trade.direction || "N/A";
  const dirEmoji = direction === "LONG" ? "ЁЯЯв" : "ЁЯФ┤";

  const entryPrice = trade.entryPrice !== undefined ? trade.entryPrice : "N/A";
  const exitPrice = trade.exitPrice !== undefined ? trade.exitPrice : "N/A";
  const size = trade.size !== undefined ? trade.size : "N/A";
  const value = trade.value !== undefined ? Number(trade.value).toFixed(2) : "N/A";
  const fundingRatePct = trade.fundingRatePct !== undefined ? Number(trade.fundingRatePct).toFixed(4) : "N/A";

  // Motivo: aceitar a nova margem do webhook (trade.margin) sem quebrar payloads legados.
  const margin = trade.margin !== undefined && trade.margin !== null ? Number(trade.margin).toFixed(4) : "N/A";

  const totalPnl = trade.lucroDolar !== undefined ? trade.lucroDolar : undefined;
  const totalPnlPct = trade.LucroPorcentagem !== undefined ? trade.LucroPorcentagem : undefined;

  const closeReason = trade.motivoFechamento || "N/A";
  const openTime = trade.openTime || "N/A";
  const closeTime = trade.closeTime || "N/A";

  // Mapeamento de motivos de fechamento
  const reasonNames = { "funding": "Funding Rate", "timeout": "Timeout", "stop_loss_pct": "Stop Loss %", "stop_loss_usd": "Stop Loss $", "trailing_stop": "Trailing Stop", "take_profit_target": "Take Profit", "exchange_sync": "Sync Exchange", "manual": "Manual" };

  let msg = ``;

  if (event === "OPEN") {
    msg += `ЁЯЪА *Opera├з├гo aberta*\n`;
    msg += `тФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБ\n\n`;
    msg += `ЁЯСд *Usu├бrio:* ${userEmail}\n`;
    msg += `ЁЯУК *Exchange:* ${exchange.toUpperCase()}\n`;
    msg += `тЪЩя╕П *Modo:* ${modeDisplay}\n`;
    msg += `ЁЯПж *Alavancagem:* ${leverage}x\n\n`;
    msg += `тФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБ\n`;
    msg += `${dirEmoji} *Par:* ${symbol}\n`;
    msg += `ЁЯзн *Dire├з├гo:* ${direction}\n`;
    msg += `ЁЯТ╡ *Pre├зo de Entrada:* $${entryPrice}\n`;
    msg += `ЁЯУж *Quantidade:* ${size}\n`;
    msg += `ЁЯТ░ *Valor Posi├з├гo:* $${value}\n`;
    msg += `*Margem:* $${margin}\n`;
    msg += `ЁЯУЙ *Funding Rate:* ${fundingRatePct}%\n\n`;
    msg += `тФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБ\n`;
    msg += `тП▒я╕П *Hor├бrio:* ${openTime}\n\n`;
    msg += `ЁЯдЦ _Vorxia Bot_`;
  } else if (event === "CLOSED") {
    const isProfit = (totalPnl !== undefined && Number(totalPnl) >= 0);
    const icon = isProfit ? "тЬЕ" : "тЭМ";
    const resultText = isProfit ? "LUCRO" : "PREJU├НZO";
    const reasonDisplay = reasonNames[closeReason] || closeReason;

    msg += `${icon} *Op Fechada тАФ ${resultText}* ${icon}\n`;
    msg += `тФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБ\n\n`;
    msg += `ЁЯСд *Usu├бrio:* ${userEmail}\n`;
    msg += `ЁЯУК *Exchange:* ${exchange.toUpperCase()}\n`;
    msg += `тЪЩя╕П *Modo:* ${modeDisplay}\n`;
    msg += `ЁЯПж *Alavancagem:* ${leverage}x\n\n`;
    msg += `тФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБ\n`;
    msg += `${dirEmoji} *Par:* ${symbol}\n`;
    msg += `ЁЯзн *Dire├з├гo:* ${direction}\n`;
    msg += `ЁЯТ╡ *Entrada:* $${entryPrice}\n`;
    msg += `ЁЯТ╡ *Sa├нda:* $${exitPrice}\n`;
    msg += `*Margem:* $${margin}\n\n`;

    const pnlFormatted = totalPnl !== undefined ? Number(totalPnl).toFixed(4) : "0.0000";
    const pnlPctFormatted = totalPnlPct !== undefined ? Number(totalPnlPct).toFixed(2) : "0.00";

    msg += `тФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБ\n`;
    msg += `ЁЯТ╡ *Resultado:* $${pnlFormatted}\n`;
    msg += `ЁЯУК *Resultado %:* ${pnlPctFormatted}%\n`;
    msg += `ЁЯУМ *Motivo:* ${reasonDisplay}\n\n`;

    msg += `тФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБтФБ\n`;
    msg += `тП▒я╕П *Abertura:* ${openTime}\n`;
    msg += `ЁЯЫС *Fechamento:* ${closeTime}\n\n`;
    msg += `ЁЯдЦ _Vorxia Bot_`;
  } else {
    msg += `ЁЯФФ *Novo Evento: ${event}*\n\n`;
    msg += `ЁЯСд *Usu├бrio:* ${userEmail}\n`;
    msg += `ЁЯУИ *Par:* ${symbol}`;
  }

  item.json.whatsappMessage = msg;
}

return $input.all();
